SELECT [ReportVendutoComprato-NonProiettato-step0].Linea AS [Line Code], [ReportVendutoComprato-NonProiettato-step0].Articolo AS No_, [ReportVendutoComprato-NonProiettato-step0].CodiceColore AS ColorCode, [ReportVendutoComprato-NonProiettato-step0].Colore AS Color, [ReportVendutoComprato-NonProiettato-step0].Marchio AS [Trademark Code], [ReportVendutoComprato-NonProiettato-step0].Stagione AS [Season Code], [ReportVendutoComprato-NonProiettato-step0].PaiaComprate AS PairsPurchased, [ReportVendutoComprato-NonProiettato-step0].PaiaVendute AS PairsSold, IIf([paiavendute]>[paiacomprate],[paiavendute]-[paiacomprate],0) AS toBuy, IIf([paiacomprate]>[paiavendute],[paiacomprate]-[paiavendute],0) AS toSell, [ReportVendutoComprato-NonProiettato-step0].Descrizione AS Description, [ReportVendutoComprato-NonProiettato-step0].Descrizione2 AS [Description 2], [ReportVendutoComprato-NonProiettato-step0].FamigliaProdotto AS [Product Family], [ReportVendutoComprato-NonProiettato-step0].GenereProdotto AS [Product Sex], [ReportVendutoComprato-NonProiettato-step0].[Collection Code], [ReportVendutoComprato-NonProiettato-step0].[Vendor No_], [ReportVendutoComprato-NonProiettato-step0].VendorName, [ReportVendutoComprato-NonProiettato-step0].manufacturer, [ReportVendutoComprato-NonProiettato-step0].manufacturername
FROM [ReportVendutoComprato-NonProiettato-step0];

